```typescript
#!/usr/bin/env tsx
// Usage: npx tsx scripts/create-quote.ts --id <id> --file <path-to-md> --component <component-source>
// Called by the generation pipeline after files are written to disk.

import { createClient } from "@libsql/client";
import { nanoid } from "nanoid";
import { readFileSync } from "fs";
import matter from "gray-matter"; // add gray-matter as devDependency

async function main() {
  const args = Object.fromEntries(
    process.argv.slice(2).reduce<string[][]>((acc, arg, i, arr) => {
      if (arg.startsWith("--")) acc.push([arg.slice(2), arr[i + 1]]);
      return acc;
    }, [])
  );

  const mdPath = args.file;
  const raw = readFileSync(mdPath, "utf-8");
  const { data: frontmatter, content } = matter(raw);
  const id = args.id || nanoid(10);

  const db = createClient({
    url: process.env.DATABASE_URL || "file:local.db",
    authToken: process.env.DATABASE_AUTH_TOKEN,
  });

  const now = new Date().toISOString();

  await db.execute({
    sql: `INSERT INTO quotes (
            id, client_name, client_email, client_company, title,
            quote_type, currency, locale, valid_until,
            raw_content, generated_component,
            status, line_items, created_at, updated_at
          ) VALUES (?, ?, ?, ?, ?, 'ai-generated', ?, ?, ?, ?, ?, 'draft', '[]', ?, ?)`,
    args: [
      id,
      frontmatter.client_name, frontmatter.client_email,
      frontmatter.client_company || "",
      frontmatter.title,
      frontmatter.currency || "USD",
      frontmatter.locale || "en",
      frontmatter.valid_until || "",
      content,
      args.component || "",
      now, now,
    ],
  });

  console.log(`Quote created: ${id}`);
  console.log(`URL: /${frontmatter.locale || "en"}/quote/${id}`);
  process.exit(0);
}

main().catch(console.error);
```

Add `gray-matter` as a devDependency (`npm install --save-dev gray-matter`). It is a zero-dependency frontmatter parser.

