import { notFound } from "next/navigation";
import { getQuoteById } from "@/features/quotes/lib/queries";
import { QuoteViewer } from "@/features/quotes/components/QuoteViewer";
import { AiQuoteShell } from "@/features/quotes/components/AiQuoteShell";
import { getQuoteComponent, quoteRegistry } from "@/features/quotes/lib/quoteRegistry";
import type { Metadata } from "next";

export const metadata: Metadata = {
  robots: { index: false, follow: false },
};

export default async function QuotePage({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  const { id } = await params;
  const quote = await getQuoteById(id);

  if (!quote) notFound();

  // Handle AI-generated quotes
  if (quote.quoteType === "ai-generated") {
    const entry = getQuoteComponent(quote.generatedComponent);
    if (entry) {
      return <AiQuoteShell quote={quote} QuoteContent={entry.QuoteContent} />;
    }
  }

  // Default to legacy QuoteViewer for line-items and blueprint types
  return <QuoteViewer quote={quote} />;
}

import type { ComponentType } from "react";
import type { Quote } from "../types";

export interface QuoteRegistryEntry {
  QuoteContent: ComponentType<{ quote: Quote }>;
}

/**
 * Registry for dynamically loading AI-generated quote components.
 * Maps generated component IDs to their corresponding React components.
 */
export const quoteRegistry = new Map<string, QuoteRegistryEntry>();

/**
 * Register an AI-generated quote component.
 * @param componentId - Unique identifier for the generated component
 * @param entry - Registry entry containing the QuoteContent component
 */
export function registerQuoteComponent(
  componentId: string,
  entry: QuoteRegistryEntry
) {
  quoteRegistry.set(componentId, entry);
}

/**
 * Retrieve a registered AI-generated quote component.
 * @param componentId - The component ID to look up
 * @returns The registry entry if found, or undefined
 */
export function getQuoteComponent(componentId?: string) {
  if (!componentId) return undefined;
  return quoteRegistry.get(componentId);
}

